// src/pages/Register.jsx

import { useState } from "react";
import axios from "axios";

export default function Register() {

  const [emailError, setEmailError] =
    useState("");

  const [form, setForm] =
    useState({

      role: "customer",

      skills: []

    });

  const jobs = [

    "Electrician",
    "Plumber",
    "Painter",
    "Carpenter",
    "Cleaner",
    "Technician",
    "Welder",
    "Driver"

  ];

  const handleSkills = (e) => {

    const values = Array.from(

      e.target.selectedOptions,

      option => option.value

    );

    setForm({

      ...form,

      skills: values

    });
  };

  const register = async () => {

    // EMAIL VALIDATION

    if (
      !form.email?.includes(
        "@gmail.com"
      )
    ) {

      setEmailError(
        "Should contain @gmail.com"
      );

      return;
    }

    // PHONE VALIDATION

    if (
      !form.phone ||
      form.phone.length !== 10
    ) {

      alert(
        "Phone number must be 10 digits"
      );

      return;
    }

    try {

      const res = await axios.post(

        "http://localhost:5000/api/auth/register",

        form

      );

      localStorage.setItem(

        "user",

        JSON.stringify(res.data.user)

      );

      if (form.role === "customer") {

        window.location =
          "/customer-dashboard";

      } else {

        window.location =
          "/labour-dashboard";

      }

    } catch (err) {

      alert(

        err.response?.data?.message ||

        "Registration Failed"

      );
    }
  };

  return (

    <div style={styles.page}>

      <div style={styles.glow1}></div>
      <div style={styles.glow2}></div>

      {/* REGISTER CARD */}

      <div style={styles.card}>

        <h1 style={styles.brand}>
          DailyMajdoor
        </h1>

        <h2 style={styles.title}>
          Register
        </h2>

        <p style={styles.subtitle}>
          Create your account
        </p>

        {/* ROLE */}

        <div style={styles.field}>

          <select
            style={styles.input}
            onChange={(e) =>
              setForm({
                ...form,
                role: e.target.value
              })
            }
          >

            <option value="customer">
              Customer
            </option>

            <option value="labour">
              Labour
            </option>

          </select>

        </div>

        {/* NAME */}

        <div style={styles.field}>

          <input
            style={styles.input}
            placeholder="Full Name"
            onChange={(e) =>
              setForm({
                ...form,
                name: e.target.value
              })
            }
          />

        </div>

        {/* EMAIL */}

        <div style={styles.field}>

          <input
            type="email"
            placeholder="Email"
            style={{
              ...styles.input,
              border: emailError
                ? "1.5px solid red"
                : "1.5px solid #f97316"
            }}
            required
            value={form.email || ""}
            onChange={(e) => {

              const value =
                e.target.value;

              setForm({
                ...form,
                email: value
              });

              if (
                !value.includes(
                  "@gmail.com"
                )
              ) {

                setEmailError(
                  "Should contain @gmail.com"
                );

              } else {

                setEmailError("");

              }

            }}
          />

          {emailError && (

            <p style={styles.error}>
              {emailError}
            </p>

          )}

        </div>

        {/* PASSWORD */}

        <div style={styles.field}>

          <input
            type="password"
            style={styles.input}
            placeholder="Password"
            required
            minLength={6}
            value={form.password || ""}
            onChange={(e) =>
              setForm({
                ...form,
                password: e.target.value
                
              })
              
            }
          />
          
        </div>

        {/* PHONE */}

        <div style={styles.field}>

          <input
            type="tel"
            placeholder="Phone Number"
            style={{
              ...styles.input,
              border:
                form.phone &&
                form.phone.length !== 10
                  ? "1.5px solid red"
                  : "1.5px solid #f97316"
            }}
            required
            maxLength={10}
            value={form.phone || ""}
            onChange={(e) => {

              const value =
                e.target.value.replace(
                  /\D/g,
                  ""
                );

              setForm({
                ...form,
                phone: value
              });

            }}
          />

          {form.phone &&
           form.phone.length !== 10 && (

            <p style={styles.error}>
              Phone number must be 10 digits
            </p>

          )}

        </div>

        {/* CITY + AREA */}

        <div style={styles.fieldRow}>

          <input
            style={styles.smallInput}
            placeholder="City"
            onChange={(e) =>
              setForm({
                ...form,
                city: e.target.value
              })
            }
          />

          <input
            style={styles.smallInput}
            placeholder="Area"
            onChange={(e) =>
              setForm({
                ...form,
                area: e.target.value
              })
            }
          />

        </div>

        {/* LABOUR SKILLS */}

        {form.role === "labour" && (

          <div style={styles.field}>

            <select
              multiple
              style={styles.multi}
              onChange={handleSkills}
            >

              {jobs.map((job, index) => (

                <option
                  key={index}
                  value={job}
                >
                  {job}
                </option>

              ))}

            </select>

          </div>

        )}

        <button
          style={styles.button}
          onClick={register}
        >
          Create Account
        </button>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#0f172a",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    padding: "20px",
    position: "relative",
    overflow: "hidden",
    fontFamily: "Arial",
    margin: 0
  },

  glow1: {
    position: "absolute",
    width: "260px",
    height: "260px",
    borderRadius: "50%",
    background: "#f97316",
    filter: "blur(120px)",
    top: "-80px",
    left: "-80px",
    opacity: 0.35
  },

  glow2: {
    position: "absolute",
    width: "220px",
    height: "220px",
    borderRadius: "50%",
    background: "#fb923c",
    filter: "blur(100px)",
    bottom: "-80px",
    right: "-80px",
    opacity: 0.3
  },

  card: {
    width: "340px",
    background: "#111827",
    border: "2px solid #f97316",
    borderRadius: "20px",
    padding: "22px",
    position: "relative",
    zIndex: 2,
    boxShadow:
      "0 10px 35px rgba(0,0,0,0.45)"
  },

  brand: {
    textAlign: "center",
    color: "#fb923c",
    margin: 0,
    marginBottom: "12px",
    fontSize: "26px"
  },

  title: {
    textAlign: "center",
    color: "white",
    margin: 0,
    fontSize: "22px"
  },

  subtitle: {
    textAlign: "center",
    color: "#9ca3af",
    marginTop: "6px",
    marginBottom: "18px",
    fontSize: "12px"
  },

  field: {
    marginBottom: "12px"
  },

  fieldRow: {
    display: "flex",
    gap: "10px",
    marginBottom: "12px"
  },

  input: {
    width: "100%",
    padding: "12px",
    borderRadius: "10px",
    border: "1px solid #f97316",
    background: "#1f2937",
    color: "white",
    boxSizing: "border-box",
    outline: "none",
    fontSize: "13px"
  },

  smallInput: {
    width: "50%",
    padding: "12px",
    borderRadius: "10px",
    border: "1px solid #f97316",
    background: "#1f2937",
    color: "white",
    boxSizing: "border-box",
    outline: "none",
    fontSize: "13px"
  },

  multi: {
    width: "100%",
    height: "85px",
    borderRadius: "10px",
    border: "1px solid #f97316",
    background: "#1f2937",
    color: "white",
    padding: "10px",
    fontSize: "13px",
    outline: "none"
  },

  error: {
    color: "red",
    fontSize: "11px",
    marginTop: "4px",
    marginBottom: "0px",
    paddingLeft: "4px",
    fontWeight: "bold"
  },

  button: {
    width: "100%",
    background:
      "linear-gradient(135deg,#f97316,#fb923c)",
    color: "white",
    padding: "12px",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer",
    fontWeight: "bold",
    marginTop: "6px",
    fontSize: "14px"
  }

};
